// Read last-synced timestamp from workflow static data.
// Returns 0 (epoch) on first run so all existing links are ingested.
const workflowStaticData = $getWorkflowStaticData('global');
const lastSynced = workflowStaticData.lastSyncedAt || 0;
return [{ json: { lastSyncedAt: lastSynced } }];

// Filter to links created after last sync timestamp.
// Also flatten nested response.response array.
const lastSynced = $input.first().json.lastSyncedAt;
const links = $input.last().json.response || [];

const newLinks = links.filter(link => {
  const created = new Date(link.createdAt).getTime();
  return created > lastSynced;
});

console.log(`Found ${links.length} total, ${newLinks.length} new since last sync`);

if (newLinks.length === 0) {
  // Nothing to do — return empty to halt downstream
  return [];
}

return newLinks.map(link => ({ json: link }));

// Format each Linkwarden link as a Markdown document for AnythingLLM.
// AnythingLLM chunks plain text well; Markdown headers improve retrieval.
const link = $input.item.json;

const tags = (link.tags || []).map(t => t.name).join(', ');
const collection = link.collection?.name || 'Uncategorized';
const createdDate = new Date(link.createdAt).toISOString().split('T')[0];

const content = [
  `# ${link.name || link.url}`,
  ``,
  `**URL:** ${link.url}`,
  `**Saved:** ${createdDate}`,
  `**Collection:** ${collection}`,
  tags ? `**Tags:** ${tags}` : null,
  ``,
  link.description ? `## Description\n${link.description}` : null,
  ``,
  link.textContent ? `## Content\n${link.textContent}` : null,
].filter(Boolean).join('\n');

return [{
  json: {
    ...link,
    markdownContent: content,
    filename: `linkwarden-${link.id}.md`,
  }
}];

// After all items processed, update the cursor to now.
// This runs once after the loop via the Merge node.
const workflowStaticData = $getWorkflowStaticData('global');
workflowStaticData.lastSyncedAt = Date.now();
console.log(`Cursor updated to ${new Date(workflowStaticData.lastSyncedAt).toISOString()}`);
return [{ json: { syncedAt: new Date(workflowStaticData.lastSyncedAt).toISOString() } }];
